package com.google.gson;
import com.google.gson.internal.Streams;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;

public class JsonParserTest {

  private JsonParser jsonParser;

  @BeforeEach
  public void setUp() {
    jsonParser = new JsonParser();
  }

  @Test
  public void parse_withValidReader_shouldReturnJsonElement() throws IOException {
    String json = "{\"key\":\"value\"}";
    Reader reader = new StringReader(json);

    JsonElement result = jsonParser.parse(reader);

    assertNotNull(result);
    // Since parseReader is static and final, we trust it returns a JsonElement for valid JSON.
  }

  @Test
  public void parse_withEmptyJson_shouldReturnJsonElement() throws IOException {
    String json = "";
    Reader reader = new StringReader(json);

    JsonElement result = jsonParser.parse(reader);

    assertNotNull(result);
  }

  @Test
  public void parse_withMalformedJson_shouldThrowJsonSyntaxException() throws IOException {
    String malformedJson = "{key:\"value\""; // Missing closing brace
    Reader reader = new StringReader(malformedJson);

    JsonSyntaxException thrown = assertThrows(JsonSyntaxException.class, () -> {
      jsonParser.parse(reader);
    });

    assertNotNull(thrown.getMessage());
  }

  @Test
  public void parse_withIOException_shouldThrowJsonIOException() {
    Reader reader = mock(Reader.class);
    try {
      when(reader.read(any(char[].class), anyInt(), anyInt())).thenThrow(new IOException("IO error"));
    } catch (IOException e) {
      // won't happen on mock setup
    }

    JsonIOException thrown = assertThrows(JsonIOException.class, () -> {
      jsonParser.parse(reader);
    });

    assertNotNull(thrown.getMessage());
  }

  @Test
  public void parse_withNullReader_shouldThrowNullPointerException() {
    assertThrows(NullPointerException.class, () -> {
      jsonParser.parse(null);
    });
  }
}
